python3 -c "
import csv
# Count questions by resolution date range
with open('market.csv') as f:
    reader = csv.DictReader(f)
    dates = {}
    for row in reader:
        rd = row['resolution_date']
        if row['is_resolved'] == 'False':
            week = rd[:10]
            if week not in dates:
                dates[week] = 0
            dates[week] += 1
    for d in sorted(dates.keys()):
        print(f'{d}: {dates[d]} questions')
"
